<span class="token keyword">import</span> <span class="token namespace">javax<span class="token punctuation">.</span>imageio<span class="token punctuation">.</span></span><span class="token class-name">ImageIO</span><span class="token punctuation">;</span>

<span class="token keyword">import</span> <span class="token keyword">static</span> <span class="token namespace">java<span class="token punctuation">.</span>awt<span class="token punctuation">.</span>image<span class="token punctuation">.</span></span><span class="token class-name">BufferedImage</span><span class="token punctuation">.</span>TYPE_INT_ARGB<span class="token punctuation">;</span>


<span class="token doc-comment comment">/**
 * jar下载地址：https://repo.e-iceblue.cn/#browse/browse:maven-public:e-iceblue，下载free的;
 * <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">></span></span>
 * 使用文档：https://www.e-iceblue.cn/tutorials.html，查看...for java的文档
 * <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">></span></span>
 * 为下列文件添加图片水印：
 * <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">></span></span>
 * word；
 * <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">></span></span>
 * excel：本质上是添加图片页眉，且在正常模式下不可见，仅在页面布局模式或打印预览模式可见；也可添加背景图片；
 * <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">></span></span>
 * ppt：本质是添加背景图片；
 * <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">></span></span>
 * pdf；
 */</span>
<span class="token annotation punctuation">@Slf4j</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">WaterMarkUtils</span> <span class="token punctuation">{</span>

    <span class="token doc-comment comment">/**
     * 100为原大小；
     * word水印缩放大小;
     */</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">int</span> SIZE <span class="token operator">=</span> <span class="token number">100</span><span class="token punctuation">;</span>

    <span class="token doc-comment comment">/**
     * 当前模块resource下的静态图片->设置透明度的背景图片
     */</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">String</span> BACKGROUND_PATH <span class="token operator">=</span> <span class="token string">"static/"</span> <span class="token operator">+</span> <span class="token string">"white.png"</span><span class="token punctuation">;</span>

    <span class="token doc-comment comment">/**
     * 仅针对excel文件：
     * 水印图片透明度设置：0->1.0f，逐渐不透明;
     */</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">Float</span> ALPHA_EXCEL <span class="token operator">=</span> <span class="token number">0.2f</span><span class="token punctuation">;</span>

    <span class="token doc-comment comment">/**
     * 仅针对ppt文件：
     * 水印图片透明度设置：0->1.0f，逐渐不透明;
     */</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">Float</span> ALPHA_PPT <span class="token operator">=</span> <span class="token number">0.2f</span><span class="token punctuation">;</span>

    <span class="token doc-comment comment">/**
     * 仅针对pdf文件：
     * 水印图片透明度设置：0->1.0f，逐渐不透明;
     */</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">Float</span> ALPHA_PDF <span class="token operator">=</span> <span class="token number">0.2f</span><span class="token punctuation">;</span>

    <span class="token doc-comment comment">/**
     * 仅针对图片：
     * 水印图片透明度设置：0->1.0f，逐渐不透明;
     */</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">Float</span> ALPHA_IMG <span class="token operator">=</span> <span class="token number">0.4f</span><span class="token punctuation">;</span>

    <span class="token doc-comment comment">/**
     * 对水印图片进行缩放的大小设置：
     * 大于370->等比缩小到370；
     * 小于370->等比放大到370；
     */</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">int</span> TARGETWIDTH <span class="token operator">=</span> <span class="token number">370</span><span class="token punctuation">;</span>

    <span class="token doc-comment comment">/**
     * 对水印图片进行缩放的大小设置：
     * 大于370->等比缩小到370；
